    testId,
    target: manifest.target,
    score: result.score,
    executionStatus: result.executionStatus,
    workspacePath: manifest.workspacePath,
    manifestPath: manifest.manifestPath,
    outputDir: runDir,
    indexPath: artifacts.indexPath,
  };
}

