}): Promise<{ score: EvaluationScore; scores?: GraderResult[] }> {
  const {
    evalCase,
    candidate,
    target,
    provider,
    evaluators,
    typeRegistry,
    attempt,
    promptInputs,
    now,
    graderProvider,
    agentTimeoutMs,
    output,
    trace,
    costUsd,
    durationMs,
    tokenUsage,
    startTime,
    endTime,
    targetResolver,
    availableTargets,
    fileChanges,
    toolCalls,
    workspacePath,
    dockerConfig,
    threshold,
    dependencyResults,
  } = options;

  if (evalCase.assertions && evalCase.assertions.length > 0) {
    return runEvaluatorList({
      evalCase,
      evaluators: evalCase.assertions,
      candidate,
      target,
      provider,
      evaluatorRegistry: evaluators,
      typeRegistry,
      attempt,
      promptInputs,
      now,
      graderProvider,
      agentTimeoutMs,
      output,
      trace,
      costUsd,
      durationMs,
      tokenUsage,
      startTime,
      endTime,
      targetResolver,
      availableTargets,
      fileChanges,
      toolCalls,
      workspacePath,
      dockerConfig,
      threshold,
      dependencyResults,
    });
  }

  const evaluatorKind = evalCase.evaluator ?? 'llm-grader';
  const activeEvaluator = evaluators[evaluatorKind] ?? evaluators['llm-grader'];
  if (!activeEvaluator) {
    throw new Error(`No evaluator registered for kind '${evaluatorKind}'`);
  }
  const implicitEvaluator =
    evaluatorKind === 'llm-grader' && !evalCase.assertions
      ? buildImplicitLlmGraderConfig(evalCase)
      : undefined;

  const score = await activeEvaluator.evaluate({
    evalCase,
    candidate,
    target,
    provider,
    attempt,
    promptInputs,
    now,
    graderProvider,
    output,
    trace,
    tokenUsage,
    costUsd,
    durationMs,
    startTime,
    endTime,
    targetResolver,
    availableTargets,
    fileChanges,
    toolCalls,
    workspacePath,
    dockerConfig,
    dependencyResults,
    ...(implicitEvaluator ? { evaluator: implicitEvaluator } : {}),
  });

  return { score };
}

function buildImplicitLlmGraderConfig(evalCase: EvalTest): LlmGraderConfig | undefined {
  if (!evalCase.preprocessors || evalCase.preprocessors.length === 0) {
    return undefined;
  }

  return {
    name: 'llm-grader',
    type: 'llm-grader',
    preprocessors: evalCase.preprocessors,
  };
}

